<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
  <title>Personal Expense Tracker</title>
  <style>
    :root {
      --bg: #f4f7fb;
      --card: #ffffff;
      --text: #1f2937;
      --muted: #64748b;
      --accent: #2563eb;
      --danger: #dc2626;
      --border: #dbe3ee;
      --success: #166534;
    }

    * { box-sizing: border-box; }

    body {
      margin: 0;
      min-height: 100vh;
      padding: 24px;
      font-family: Arial, Helvetica, sans-serif;
      color: var(--text);
      background: var(--bg);
    }

    main {
      width: min(900px, 100%);
      margin: 0 auto;
    }

    h1 {
      margin: 0 0 20px;
      font-size: 1.8rem;
    }

    h2 {
      margin: 0 0 14px;
      font-size: 1.1rem;
    }

    .card {
      margin-bottom: 18px;
      padding: 20px;
      background: var(--card);
      border: 1px solid var(--border);
      border-radius: 12px;
      box-shadow: 0 3px 12px rgba(15, 23, 42, 0.05);
    }

    .form-grid,
    .filter-grid {
      display: grid;
      grid-template-columns: repeat(4, minmax(0, 1fr));
      gap: 14px;
      align-items: end;
    }

    .filter-grid {
      grid-template-columns: repeat(3, minmax(0, 1fr));
    }

    label {
      display: block;
      margin-bottom: 6px;
      font-size: 0.86rem;
      font-weight: bold;
      color: #334155;
    }

    input,
    select,
    button {
      width: 100%;
      min-height: 40px;
      font: inherit;
      border-radius: 7px;
    }

    input,
    select {
      padding: 8px 10px;
      color: var(--text);
      background: #fff;
      border: 1px solid #b9c5d4;
    }

    button {
      padding: 8px 12px;
      cursor: pointer;
      color: #fff;
      font-weight: bold;
      border: 0;
      background: var(--accent);
    }

    button:hover { filter: brightness(0.94); }

    #form-error {
      min-height: 1.2em;
      margin: 12px 0 0;
      color: var(--danger);
      font-size: 0.9rem;
      font-weight: bold;
    }

    .summary-row {
      display: flex;
      flex-wrap: wrap;
      align-items: center;
      justify-content: space-between;
      gap: 14px;
      margin-bottom: 16px;
    }

    #total {
      font-size: 1.5rem;
      font-weight: bold;
      color: var(--success);
    }

    #category-summary {
      display: grid;
      grid-template-columns: repeat(4, minmax(120px, 1fr));
      gap: 10px;
    }

    .cat-total {
      padding: 10px;
      font-size: 0.9rem;
      background: #f8fafc;
      border: 1px solid var(--border);
      border-radius: 8px;
    }

    #expense-list {
      display: grid;
      gap: 10px;
    }

    .expense {
      display: grid;
      grid-template-columns: 1.1fr 1fr 1fr 1.5fr auto;
      gap: 12px;
      align-items: center;
      padding: 13px;
      background: #fff;
      border: 1px solid var(--border);
      border-radius: 9px;
    }

    .expense-amount {
      font-weight: bold;
      color: var(--success);
    }

    .expense-category {
      text-transform: capitalize;
    }

    .expense-note {
      overflow: hidden;
      color: var(--muted);
      text-overflow: ellipsis;
      white-space: nowrap;
    }

    .exp-del {
      width: auto;
      min-height: 34px;
      padding: 6px 10px;
      background: var(--danger);
    }

    .empty {
      padding: 20px;
      text-align: center;
      color: var(--muted);
      border: 1px dashed #b9c5d4;
      border-radius: 9px;
    }

    @media (max-width: 700px) {
      .form-grid,
      .filter-grid {
        grid-template-columns: 1fr 1fr;
      }

      .expense {
        grid-template-columns: 1fr 1fr auto;
      }

      .expense-note {
        grid-column: 1 / -1;
      }

      #category-summary {
        grid-template-columns: 1fr 1fr;
      }
    }

    @media (max-width: 430px) {
      body { padding: 14px; }
      .form-grid,
      .filter-grid { grid-template-columns: 1fr; }
      .expense { grid-template-columns: 1fr 1fr; }
      .exp-del { grid-column: 1 / -1; width: 100%; }
    }
  </style>
</head>
<body>
  <main>
    <h1>Personal Expense Tracker</h1>

    <section class="card">
      <h2>Add Expense</h2>
      <form id="expense-form" novalidate>
        <div class="form-grid">
          <div>
            <label for="amount">Amount</label>
            <input id="amount" type="number" min="0.01" step="0.01" inputmode="decimal" placeholder="0.00">
          </div>

          <div>
            <label for="category">Category</label>
            <select id="category">
              <option value="groceries">Groceries</option>
              <option value="transport">Transport</option>
              <option value="bills">Bills</option>
              <option value="fun">Fun</option>
            </select>
          </div>

          <div>
            <label for="date">Date</label>
            <input id="date" type="date">
          </div>

          <div>
            <label for="note">Note (optional)</label>
            <input id="note" type="text" maxlength="120" placeholder="What was this for?">
          </div>

          <div>
            <button id="add-expense" type="submit">Add Expense</button>
          </div>
        </div>
        <p id="form-error" aria-live="polite"></p>
      </form>
    </section>

    <section class="card">
      <h2>Filters</h2>
      <div class="filter-grid">
        <div>
          <label for="filter-category">Category</label>
          <select id="filter-category">
            <option value="all">All categories</option>
            <option value="groceries">Groceries</option>
            <option value="transport">Transport</option>
            <option value="bills">Bills</option>
            <option value="fun">Fun</option>
          </select>
        </div>
        <div>
          <label for="filter-from">From date</label>
          <input id="filter-from" type="date">
        </div>
        <div>
          <label for="filter-to">To date</label>
          <input id="filter-to" type="date">
        </div>
      </div>
    </section>

    <section class="card">
      <div class="summary-row">
        <h2>Visible Total</h2>
        <div>$<span id="total">0.00</span></div>
      </div>
      <div id="category-summary">
        <div class="cat-total" data-cat="groceries">Groceries: $0.00</div>
        <div class="cat-total" data-cat="transport">Transport: $0.00</div>
        <div class="cat-total" data-cat="bills">Bills: $0.00</div>
        <div class="cat-total" data-cat="fun">Fun: $0.00</div>
      </div>
    </section>

    <section class="card">
      <h2>Expenses</h2>
      <div id="expense-list" aria-live="polite"></div>
    </section>
  </main>

  <script>
    (function () {
      const STORAGE_KEY = "personal-expense-tracker-expenses";
      const categories = ["groceries", "transport", "bills", "fun"];

      const form = document.getElementById("expense-form");
      const amountInput = document.getElementById("amount");
      const categoryInput = document.getElementById("category");
      const dateInput = document.getElementById("date");
      const noteInput = document.getElementById("note");
      const errorElement = document.getElementById("form-error");
      const listElement = document.getElementById("expense-list");
      const totalElement = document.getElementById("total");
      const filterCategory = document.getElementById("filter-category");
      const filterFrom = document.getElementById("filter-from");
      const filterTo = document.getElementById("filter-to");

      let expenses = loadExpenses();

      function loadExpenses() {
        try {
          const saved = JSON.parse(localStorage.getItem(STORAGE_KEY));
          if (!Array.isArray(saved)) return [];
          return saved.filter(function (item) {
            return item &&
              typeof item.id === "string" &&
              typeof item.category === "string" &&
              categories.includes(item.category) &&
              typeof item.date === "string" &&
              Number.isFinite(Number(item.amount)) &&
              Number(item.amount) > 0;
          }).map(function (item) {
            return {
              id: item.id,
              amount: Number(item.amount),
              category: item.category,
              date: item.date,
              note: typeof item.note === "string" ? item.note : ""
            };
          });
        } catch (error) {
          return [];
        }
      }

      function saveExpenses() {
        localStorage.setItem(STORAGE_KEY, JSON.stringify(expenses));
      }

      function formatAmount(value) {
        return Number(value).toFixed(2);
      }

      function visibleExpenses() {
        const chosenCategory = filterCategory.value;
        const from = filterFrom.value;
        const to = filterTo.value;

        return expenses.filter(function (expense) {
          const categoryMatches = chosenCategory === "all" || expense.category === chosenCategory;
          const fromMatches = !from || expense.date >= from;
          const toMatches = !to || expense.date <= to;
          return categoryMatches && fromMatches && toMatches;
        });
      }

      function render() {
        const visible = visibleExpenses();
        listElement.innerHTML = "";

        if (visible.length === 0) {
          const empty = document.createElement("div");
          empty.className = "empty";
          empty.textContent = "No expenses match the current filters.";
          listElement.appendChild(empty);
        } else {
          visible.forEach(function (expense) {
            const row = document.createElement("div");
            row.className = "expense";
            row.dataset.id = expense.id;

            const amount = document.createElement("div");
            amount.className = "expense-amount";
            amount.textContent = "$" + formatAmount(expense.amount);

            const category = document.createElement("div");
            category.className = "expense-category";
            category.textContent = expense.category;

            const date = document.createElement("div");
            date.textContent = expense.date;

            const note = document.createElement("div");
            note.className = "expense-note";
            note.textContent = expense.note || "—";
            note.title = expense.note || "";

            const deleteButton = document.createElement("button");
            deleteButton.type = "button";
            deleteButton.className = "exp-del";
            deleteButton.textContent = "Delete";
            deleteButton.setAttribute("aria-label", "Delete expense");

            deleteButton.addEventListener("click", function () {
              expenses = expenses.filter(function (item) {
                return item.id !== expense.id;
              });
              saveExpenses();
              render();
            });

            row.append(amount, category, date, note, deleteButton);
            listElement.appendChild(row);
          });
        }

        const totals = {
          groceries: 0,
          transport: 0,
          bills: 0,
          fun: 0
        };

        visible.forEach(function (expense) {
          totals[expense.category] += expense.amount;
        });

        const grandTotal = visible.reduce(function (sum, expense) {
          return sum + expense.amount;
        }, 0);

        totalElement.textContent = formatAmount(grandTotal);

        categories.forEach(function (category) {
          const element = document.querySelector('.cat-total[data-cat="' + category + '"]');
          element.textContent =
            category.charAt(0).toUpperCase() + category.slice(1) +
            ": $" + formatAmount(totals[category]);
        });
      }

      form.addEventListener("submit", function (event) {
        event.preventDefault();

        const rawAmount = amountInput.value.trim();
        const amount = Number(rawAmount);
        const date = dateInput.value;

        if (!rawAmount || !Number.isFinite(amount) || amount <= 0 || !date) {
          errorElement.textContent = "Please enter a positive numeric amount and select a date.";
          return;
        }

        expenses.unshift({
          id: String(Date.now()) + "-" + Math.random().toString(16).slice(2),
          amount: amount,
          category: categoryInput.value,
          date: date,
          note: noteInput.value.trim()
        });

        saveExpenses();
        errorElement.textContent = "";
        amountInput.value = "";
        noteInput.value = "";
        render();
        amountInput.focus();
      });

      [filterCategory, filterFrom, filterTo].forEach(function (input) {
        input.addEventListener("input", render);
        input.addEventListener("change", render);
      });

      render();
    })();
  </script>
</body>
</html>
